void print_queue(PriorityQueue *pq) {
    if (!pq || !pq->data) return;

    for (int i = 0; i < pq->size; i++) {
        printf("%d ", *(int*)pq->data[i]);
    }
    printf("\n");
}

int parent(int i) {
    return (i - 1) / 2;
}

int left(int i) {
    return 2 * i + 1;
}

int right(int i) {
    return 2 * i + 2;
}

void swap(void **a, void **b) {
    void *temp = *a;
    *a = *b;
    *b = temp;
}

void heapify_up(PriorityQueue *pq, int idx) {
    if (!pq || !pq->cmp || idx == 0) return;

    int p = parent(idx);
    // For a min-heap, we want smaller values at the top
    if (pq->cmp(pq->data[idx], pq->data[p]) < 0) {
        swap(&pq->data[idx], &pq->data[p]);
        heapify_up(pq, p);
    }
}

void heapify_down(PriorityQueue *pq, int idx) {
    if (!pq || !pq->cmp) return;

    int smallest = idx;
    int l = left(idx);
    int r = right(idx);

    // Check if left child is smaller
    if (l < pq->size && pq->cmp(pq->data[l], pq->data[smallest]) < 0) {
        smallest = l;
    }

    // Check if right child is smaller
    if (r < pq->size && pq->cmp(pq->data[r], pq->data[smallest]) < 0) {
        smallest = r;
    }

    // If smallest is not the current node, swap and continue heapifying
    if (smallest != idx) {
        swap(&pq->data[idx], &pq->data[smallest]);
        heapify_down(pq, smallest);
    }
}

void pq_init(PriorityQueue *pq, Comparator cmp) {
    pq->capacity = INITIAL_CAPACITY;
    pq->size = 0;
    pq->cmp = cmp;  // Important to initialize this!
    pq->data = (void **)malloc(sizeof(void *) * pq->capacity);
    if (pq->data == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
}

void pq_insert(PriorityQueue *pq, void *node) {
    if (pq->size == pq->capacity) {
        pq->capacity *= 2;
        pq->data = (void **)realloc(pq->data, sizeof(void *) * pq->capacity);
        if (pq->data == NULL) {
            fprintf(stderr, "Memory reallocation failed\n");
            exit(EXIT_FAILURE);
        }
    }

    pq->data[pq->size] = node;
    heapify_up(pq, pq->size);
    pq->size++;
}

void *pq_delete(PriorityQueue *pq) {
    if (pq_is_empty(pq)) {
        return NULL;
    }

    void *root = pq->data[0];
    pq->data[0] = pq->data[pq->size - 1];
    pq->size--;

    if (!pq_is_empty(pq)) {
        heapify_down(pq, 0);
    }

    return root;
}

int pq_is_empty(PriorityQueue *pq) {
    return pq->size == 0;
}

void pq_destroy(PriorityQueue *pq) {
    free(pq->data);
    pq->data = NULL;
    pq->size = 0;
    pq->capacity = 0;
}

