static int find_key_index(ListPtr L, char *key) {
    if (L == NULL || key == NULL) {
        return -1;
    }

    for (int i = 0; i < lengthList(L); i++) {
        KVPair *kvp = (KVPair *)getList(L, i);
        if (kvp != NULL && kvp->key != NULL && strcmp(kvp->key, key) == 0) {
