    // Initialize each slot with an empty list
    for (int i = 0; i < hash_table_size; i++) {
        d->hash_table[i] = createList(dataPrinter);
        if (d->hash_table[i] == NULL) {
            // Clean up already created lists on failure
            for (int j = 0; j < i; j++) {
                destroyList(&d->hash_table[j]);
            }
            free(d->hash_table);
            free(d);
            return NULL;
        }
    }

    return d;
}

void dictionary_destroy(Dictionary *d) {
    if (d == NULL) {
        return;
    }

    // Free all lists and their contents
    for (int i = 0; i < d->slots; i++) {
        ListPtr list = d->hash_table[i];
        if (list != NULL) {
            // Free all KVPairs in the list
            while (lengthList(list) > 0) {
                KVPair *kvp = (KVPair *)deleteList(list, 0);
                if (kvp != NULL) {
                    free(kvp->key);
                    free(kvp->value);
                    free(kvp);
                }
            }
            destroyList(&d->hash_table[i]);
        }
    }

    free(d->hash_table);
    free(d);
}

bool dictionary_insert(Dictionary *D, KVPair *elem) {
    if (D == NULL || elem == NULL || elem->key == NULL) {
        return false;
    }

    // Calculate hash index
    unsigned int index = ht_hash(elem->key, D->slots);
    ListPtr list = D->hash_table[index];

    // Check if key already exists
    if (find_key_index(list, elem->key) != -1) {
        return false;  // Key already exists
    }

    // Insert the KVPair into the list at this slot
    if (appendList(list, elem)) {
        D->size++;
        return true;
    }

    return false;
}

KVPair *dictionary_delete(Dictionary *D, char *key) {
    if (D == NULL || key == NULL) {
        return NULL;
    }

    // Calculate hash index
    unsigned int index = ht_hash(key, D->slots);
    ListPtr list = D->hash_table[index];

    // Find the key in the list
    int key_index = find_key_index(list, key);
    if (key_index == -1) {
        return NULL;  // Key not found
    }

    // Delete the KVPair from the list
    KVPair *kvp = (KVPair *)deleteList(list, key_index);
    if (kvp != NULL) {
        D->size--;
    }

    return kvp;
}

KVPair *dictionary_find(Dictionary *D, char *k) {
    if (D == NULL || k == NULL) {
        return NULL;
    }

    // Calculate hash index
    unsigned int index = ht_hash(k, D->slots);
    ListPtr list = D->hash_table[index];

    // Find the key in the list
    int key_index = find_key_index(list, k);
    if (key_index == -1) {
        return NULL;  // Key not found
    }

    return (KVPair *)getList(list, key_index);
}

void dictionary_print(Dictionary *D) {
    if (D == NULL) {
        return;
    }

    // Iterate through all slots in the hash table
    for (int i = 0; i < D->slots; i++) {
        ListPtr list = D->hash_table[i];
        if (list != NULL) {
            // Print all KVPairs in this slot's list
            for (int j = 0; j < lengthList(list); j++) {
                KVPair *kvp = (KVPair *)getList(list, j);
                if (kvp != NULL) {
                    printf("%s: %s\n", kvp->key, (char *)kvp->value);
                }
            }
        }
    }
}

